// ===== XOR =====
function _x(d,k){
  let r="";
  for(let i=0;i<d.length;i++){
    r+=String.fromCharCode(
      d.charCodeAt(i)^k.charCodeAt(i%k.length)
    );
  }
  return r;
}

// ===== DECODE =====
function _d(){
  let d=_data;
  d=decodeURIComponent(d);
  d=_x(d,_k2);
  d=(typeof atob==="function"
    ? atob(d)
    : Buffer.from(d,"base64").toString());
  d=_x(d,_k1);
  return d;
}

// ===== CHẠY TRONG CÙNG CONTEXT =====
(function(){
  try{
    eval(_d()); // 🔥 giữ nguyên scope Tampermonkey
  }catch(e){
    console.error("ERR:",e);
  }
})();
